class Solution {
public:
    vector<int> memLeak(int memory1, int memory2) {
        vector<int> result;
        int temp1 = memory1, temp2 = memory2;
        int leakTime = 0, leakMemory1 = temp1, leakMemory2 = temp2;

        while (leakTime <= temp1 && leakTime <= temp2) {
            leakTime++;
            leakMemory1 = min(leakMemory1, temp1);
            leakMemory2 = min(leakMemory2, temp2);
        }

        result.push_back(leakTime);
        result.push_back(leakMemory1);
        result.push_back(leakMemory2);

        return result;
    }
};
